const run = $('Run persistent Bluesky monitoring Task').first().json;
const rows = $input.all()
  .map((item, rowIndex) => ({ post: item.json, rowIndex }))
  .filter(({ post }) => post && Object.keys(post).length > 0);

if (rows.length === 0) {
  return [{ json: { hasRecord: false, runId: run.id, runStatus: run.status, datasetId: run.defaultDatasetId } }];
}

return rows.map(({ post, rowIndex }) => {
  const hasIdentity = typeof post.uri === 'string' && post.uri.length > 0
    && typeof post.url === 'string' && post.url.length > 0;

  if (!hasIdentity) {
    const rowIdentity = `row:${rowIndex}`;
    const diagnostic = {
      recordType: 'malformed-dataset-row',
      code: 'MISSING_REQUIRED_IDENTITY',
      product: 'bluesky',
      runId: String(run.id ?? ''),
      datasetId: String(run.defaultDatasetId ?? ''),
      rowIndex,
      requiredFields: ['uri', 'url'],
    };

    return { json: {
      hasRecord: true,
      isDiagnostic: true,
      deliveryKey: `bluesky:diagnostic:${encodeURIComponent(String(run.id ?? 'unknown-run'))}:${rowIdentity}`,
      product: 'bluesky',
      sourceId: `diagnostic:${rowIdentity}`,
      sourceUrl: '',
      title: 'Malformed Bluesky dataset row',
      observedAt: null,
      runId: run.id,
      runStatus: run.status,
      datasetId: run.defaultDatasetId,
      payloadJson: JSON.stringify(diagnostic),
      normalized: null,
      diagnostic,
    } };
  }

  const normalized = {
    postUri: post.uri,
    postUrl: post.url,
    authorHandle: post.author?.handle ?? '',
    authorDisplayName: post.author?.displayName ?? '',
    text: post.text ?? '',
    createdAt: post.createdAt ?? null,
    matchedTerms: post.matchedTerms ?? [],
    matchSource: post.source ?? null,
    isNew: post.isNew === true,
    metrics: {
      likes: post.likeCount ?? 0,
      reposts: post.repostCount ?? 0,
      replies: post.replyCount ?? 0,
      quotes: post.quoteCount ?? 0,
    },
  };

  return { json: {
    hasRecord: true,
    isDiagnostic: false,
    deliveryKey: `bluesky:${post.uri}`,
    product: 'bluesky',
    sourceId: post.uri,
    sourceUrl: post.url,
    title: post.author?.handle ?? '',
    observedAt: post.createdAt ?? post.indexedAt ?? null,
    runId: run.id,
    runStatus: run.status,
    datasetId: run.defaultDatasetId,
    payloadJson: JSON.stringify(normalized),
    normalized,
  } };
});

const run = $('Run persistent Bluesky monitoring Task').first().json;
const prepared = $('Prepare dataset records').all().filter((item) => item.json.hasRecord === true);
const diagnosticRecordsPersisted = prepared.filter((item) => item.json.isDiagnostic === true).length;
const validRecordsPersisted = prepared.length - diagnosticRecordsPersisted;
const recordsPersisted = prepared.length;
const result = {
  runId: run.id,
  status: run.status,
  defaultDatasetId: run.defaultDatasetId ?? null,
  datasetRecordCount: recordsPersisted,
  recordsPersisted,
  validRecordsPersisted,
  diagnosticRecordsPersisted,
  terminalFailure: run.status !== 'SUCCEEDED',
};

if (run.status !== 'SUCCEEDED') {
  throw new Error(`Apify Task run ${run.id} finished ${run.status} after ${recordsPersisted} committed dataset record(s) were idempotently persisted (${diagnosticRecordsPersisted} malformed-row diagnostic record(s))`);
}

return [{ json: result }];

const run = $('Run persistent Bluesky monitoring Task').first().json;
const result = { runId: run.id, status: run.status, defaultDatasetId: null, datasetRecordCount: 0, recordsPersisted: 0, terminalFailure: run.status !== 'SUCCEEDED', diagnostic: 'Terminal run has no defaultDatasetId; no dataset request was attempted.' };
if (run.status !== 'SUCCEEDED') throw new Error(`Apify Task run ${run.id} finished ${run.status} without a defaultDatasetId; no records were available to ingest`);
return [{ json: result }];
